import{c as e}from"./app.b2da6103.js";import{_ as c}from"./plugin-vue_export-helper.21dcd24c.js";const o={},d=e('<p>\u77E5\u6211\u8005\u8C13\u6211\u5FC3\u5FE7\uFF0C\u4E0D\u77E5\u6211\u8005\u8C13\u6211\u4F55\u6C42</p><blockquote><p>\u9605\u8BFB\u672C\u6587\u524D\u7F6E\u77E5\u8BC6\uFF1AVue.js\u6570\u636E\u54CD\u5E94\u7684\u7B80\u5355\u5B9E\u73B0\uFF0C\u53EF\u8F6C\u9605\u6B64\u6587<a href="https://juejin.cn/post/7069644797778067487" target="_blank" rel="noopener noreferrer">-Vue.js\u4E2D\u4E0D\u5BB9\u6613\u7684\u6570\u636E\u54CD\u5E94\u5B9E\u73B0</a></p></blockquote><h2 id="\u5F15\u8A00" tabindex="-1"><a class="header-anchor" href="#\u5F15\u8A00" aria-hidden="true">#</a> \u5F15\u8A00</h2><p>\u8BA1\u7B97\u5C5E\u6027\u5141\u8BB8\u6211\u4EEC\u58F0\u660E\u6027\u5730\u8BA1\u7B97\u63A8\u5BFC\u503C\u3002\u7136\u800C\uFF0C\u5728\u6709\u4E9B\u60C5\u51B5\u4E0B\uFF0C\u4E3A\u4E86\u5E94\u5BF9\u4E00\u4E9B\u72B6\u6001\u7684\u53D8\u5316\uFF0C\u6211\u4EEC\u9700\u8981\u8FD0\u884C\u4E00\u4E9B\u201C\u526F\u4F5C\u7528\u201D\uFF1A\u4F8B\u5982\u66F4\u6539 DOM\uFF0C\u6216\u8005\u6839\u636E\u5F02\u6B65\u64CD\u4F5C\u7684\u7ED3\u679C\uFF0C\u53BB\u4FEE\u6539\u53E6\u4E00\u5904\u7684\u72B6\u6001\uFF0C\u4E3A\u4E86\u6EE1\u8DB3\u8FD9\u4E00\u9700\u6C42\uFF0CVue.js\u5C31\u8BBE\u8BA1\u4E86\u4FA6\u542C\u5668<code>watch</code>\u3002\u63A5\u4E0B\u6765\uFF0C\u8BA9\u6211\u4EEC\u4E00\u8D77\u6765\u63A2\u7A76\u4E00\u4E0B<code>watch</code>\u7684\u5B9E\u73B0\u539F\u7406\u3002</p><h2 id="\u4E86\u89E3watch" tabindex="-1"><a class="header-anchor" href="#\u4E86\u89E3watch" aria-hidden="true">#</a> \u4E86\u89E3<code>watch</code></h2><p>\u6240\u8C13<code>watch</code>\uFF0C\u5176\u672C\u8D28\u5C31\u662F\u89C2\u6D4B\u4E00\u4E2A\u54CD\u5E94\u5F0F\u6570\u636E\uFF0C\u5F53\u6570\u636E\u53D1\u751F\u53D8\u5316\u65F6\u901A\u77E5\u5E76\u6267\u884C\u54CD\u5E94\u7684\u56DE\u8C03\u51FD\u6570\u3002\u5176\u5B9E\u5728<a href="https://vuejs.org/api/reactivity-core.html#watch" target="_blank" rel="noopener noreferrer">Vue.js\u5B98\u65B9\u6587\u6863</a>\u4E2D\u5BF9<code>watch</code>\u6709\u8BE6\u7EC6\u7684\u7C7B\u578B\u5B9A\u4E49\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/a04b6a523ec24a8ca90b45a570bbb87a~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (87).png"></p><p>\u901A\u8FC7\u4E0A\u56FE\u53EF\u521D\u6B65\u7AA5\u89C1<code>watch</code>\u7684\u5185\u90E8\u5B9E\u73B0\uFF1A\u4EE5\u201C\u76D1\u542C\u5355\u4E2A\u6570\u636E\u6E90\u201D\u4E3A\u4F8B\uFF0C<code>watch</code>\u51FD\u6570\u63D0\u4F9B\u4E86\u4E09\u4E2A\u53C2\u6570\uFF0C<code>source</code>\u662F\u88AB\u76D1\u542C\u7684\u54CD\u5E94\u5F0F\u6570\u636E\u6E90\uFF0C<code>callbak</code>\u662F\u6BCF\u5F53<code>source</code>\u53D8\u5316\u65F6\u8981\u6267\u884C\u7684\u56DE\u8C03\u51FD\u6570\uFF0C<code>options</code>\u7C7B\u4F3C\u4E8E<code>effect</code>\u51FD\u6570\u7684<code>options</code>\uFF0C\u7528\u6765\u63A7\u5236<code>callback</code>\u5982\u4F55\u6267\u884C\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u8BA9\u6211\u4EEC\u4EE5\u4FA6\u542C\u5355\u4E2A\u6570\u636E\u6E90\u4E3A\u4F8B\uFF0C\u7B80\u5355\u63A2\u7A76\u4E00\u4E0BVue.js\u4E2D\u4FA6\u542C\u5668<code>watch</code>\u7684\u5B9E\u73B0\u539F\u7406</p><h2 id="\u5229\u7528effect\u5C01\u88C5watch" tabindex="-1"><a class="header-anchor" href="#\u5229\u7528effect\u5C01\u88C5watch" aria-hidden="true">#</a> \u5229\u7528<code>effect</code>\u5C01\u88C5<code>watch</code></h2><p>\u8FD8\u8BB0\u5F97<code>effect</code>\u51FD\u6570\u5417\uFF1F\u5982\u4E0B\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/166a13a4ec11474aac06d772531eee49~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (88).png"></p><p>\u5982\u679C\u4E00\u4E2A\u526F\u4F5C\u7528\u51FD\u6570<code>fn</code>\u8BFB\u53D6\u4E86\u4E00\u4E2A\u54CD\u5E94\u5F0F\u7684\u503C<code>obj.text</code>\uFF0C\u90A3\u4E48\u901A\u8FC7\u8C03\u7528<code>effect(fn)</code>\u5C31\u53EF\u4EE5\u7B80\u5355\u5B9E\u73B0<code>fn</code>\u4E0E<code>obj.text</code>\u7684\u7B80\u5355\u7ED1\u5B9A\uFF0C\u5373\u6BCF\u5F53<code>obj.text</code>\u53D1\u751F\u53D8\u5316\u65F6\uFF0C\u90FD\u4F1A\u91CD\u65B0\u6267\u884C\u4E00\u6B21<code>fn</code>\uFF1B\u53C8<code>effect</code>\u7B2C\u4E8C\u4E2A\u9009\u9879\u53C2\u6570<code>options</code>\u53EF\u4EE5\u4F20\u5165\u4E00\u4E2A\u8C03\u5EA6\u51FD\u6570<code>scheduler</code>\u63A7\u5236<code>fn</code>\u7684\u6267\u884C\uFF0C\u5219\u5F53<code>options.scheduler</code>\u5B58\u5728\u65F6\uFF0C\u6BCF\u6B21<code>obj.text</code>\u53D1\u751F\u53D8\u5316\u90FD\u4F1A\u91CD\u65B0\u6267\u884C<code>scheduler(effectFn)</code>\u3002\u5176\u5B9E\uFF0C\u8FD9\u4E2A<code>scheduler</code>\u5C31\u76F8\u5F53\u4E8E\u4E00\u4E2A\u56DE\u8C03\u51FD\u6570\uFF0C<code>watch</code>\u7684\u5B9E\u73B0\u5C31\u5229\u7528\u4E86\u8FD9\u4E00\u70B9\uFF0C\u8BF7\u770B\u4EE3\u7801\uFF1A</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/fa6dbfb03f4d46f38f421ada1c3a22fa~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (91).png"></p><p>\u8FD9\u6BB5\u4EE3\u7801\u5C01\u88C5\u4E86\u4E00\u4E2A\u7B80\u5355\u7684\u4FA6\u542C\u5668<code>watch</code>\uFF0C\u5728\u51FD\u6570\u5185\u90E8\u901A\u8FC7\u8C03\u7528<code>effect</code>\u5B9E\u73B0<code>source.foo</code>\u4E0E\u526F\u4F5C\u7528\u51FD\u6570\u7684\u7ED1\u5B9A\uFF0C\u901A\u8FC7\u8BBE\u7F6E<code>scheduler</code>\u6765\u5B9E\u73B0\u7528\u56DE\u8C03\u51FD\u6570<code>cb</code>\u66FF\u4EE3\u539F\u672C\u5E94\u6267\u884C\u7684\u526F\u4F5C\u7528\u51FD\u6570\u3002\u6B64\u65F6\uFF0C\u6BCF\u5F53<code>source.foo</code>\u53D1\u751F\u53D8\u5316\uFF0C\u90FD\u4F1A\u6267\u884C\u56DE\u8C03\u51FD\u6570<code>cb</code>\u3002</p><h2 id="\u5B9E\u73B0\u4FA6\u542C\u54CD\u5E94\u5F0F\u6570\u636E\u6240\u6709\u5C5E\u6027" tabindex="-1"><a class="header-anchor" href="#\u5B9E\u73B0\u4FA6\u542C\u54CD\u5E94\u5F0F\u6570\u636E\u6240\u6709\u5C5E\u6027" aria-hidden="true">#</a> \u5B9E\u73B0\u4FA6\u542C\u54CD\u5E94\u5F0F\u6570\u636E\u6240\u6709\u5C5E\u6027</h2><p>\u5728\u4E0A\u4E00\u8282\u7684\u5B9E\u73B0\u4E2D\uFF0C\u662F\u901A\u8FC7\u89E6\u53D1\u4E00\u4E2A\u6307\u5B9A\u7684\u5C5E\u6027\u503C<code>source.foo</code>\u7684\u8BFB\u53D6\u6765\u5B9E\u73B0\u5BF9\u54CD\u5E94\u5F0F\u6570\u636E<code>source</code>\u7684\u4FA6\u542C\uFF0C\u5F88\u660E\u663E\uFF0C\u5982\u679C\u662F<code>source</code>\u7684\u5176\u4ED6\u5C5E\u6027\uFF0C\u6BD4\u5982<code>source.bar</code>\u53D1\u751F\u53D8\u5316\u5C31\u5E76\u4E0D\u4F1A\u6210\u529F\u4FA6\u542C\u5230\uFF0C\u5373<code>source.bar</code>\u53D1\u751F\u53D8\u5316\u4E0D\u4F1A\u6267\u884C\u56DE\u8C03\u51FD\u6570<code>cb</code>\u3002\u63A5\u4E0B\u6765\u6211\u4EEC\u5C31\u9700\u8981\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\uFF1A\u5B9E\u73B0\u53EA\u8981\u5BF9<code>source</code>\u8FDB\u884C\u4E86\u4FA6\u542C\uFF0C\u90A3\u4E48<code>source</code>\u4EFB\u610F\u5C5E\u6027\u503C\u53D1\u751F\u53D8\u5316\u90FD\u4F1A\u89E6\u53D1<code>cb</code>\u7684\u6267\u884C\u3002</p><p>\u53EF\u4EE5\u8BBE\u8BA1\u4E00\u4E2A\u901A\u7528\u7684<code>traverse</code>\u51FD\u6570\u6765\u5B9E\u73B0\u5BF9<code>source</code>\u6240\u6709\u5C5E\u6027\u7684\u9012\u5F52\u8BFB\u53D6\uFF1A</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/55372a7f6353478fba8eb7426e74e390~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (92).png"></p><p>\u5982\u4E0A\u8FF0\u4EE3\u7801\u6240\u793A\uFF0C<code>traverse(source)</code>\u4F1A\u904D\u5386\u8BFB\u53D6<code>source</code>\u7684\u6240\u6709\u5C5E\u6027\u503C\u4EE5\u5B9E\u73B0\u5BF9\u6574\u4E2A<code>source</code>\u7684\u4FA6\u542C</p><h2 id="\u5B9E\u73B0\u4FA6\u542C\u8BA1\u7B97\u5C5E\u6027" tabindex="-1"><a class="header-anchor" href="#\u5B9E\u73B0\u4FA6\u542C\u8BA1\u7B97\u5C5E\u6027" aria-hidden="true">#</a> \u5B9E\u73B0\u4FA6\u542C\u8BA1\u7B97\u5C5E\u6027</h2><p>\u6211\u5728\u4E0A\u4E00\u7BC7\u7B14\u8BB0-<a href="https://juejin.cn/post/7070105283078406152#heading-1" target="_blank" rel="noopener noreferrer">\u7B80\u5355\u5B9E\u73B0Vue.js\u4E2D\u7684\u8BA1\u7B97\u5C5E\u6027</a>\u4E2D\u5BF9\u8BA1\u7B97\u5C5E\u6027\u4F5C\u4E86\u521D\u6B65\u7684\u89E3\u6790\uFF0C\u8BA1\u7B97\u5C5E\u6027\u5B9E\u73B0\u7684\u4E00\u4E2A\u5173\u952E\u70B9\u5C31\u662F<code>getter</code>\u3002\u5176\u5B9E\uFF0C\u5728Vue.js\u5B9E\u73B0\u7684\u4FA6\u542C\u5668<code>watch</code>\u5C31\u53EF\u4EE5\u4FA6\u542C\u8BA1\u7B97\u5C5E\u6027\uFF0C\u4F46\u6211\u4EEC\u73B0\u5728\u6240\u5B9E\u73B0\u7684<code>watch</code>\u8FD8\u505A\u4E0D\u5230\u8FD9\u4E00\u70B9\uFF0C\u63A5\u4E0B\u6765\u8BA9\u6211\u4EEC\u4E00\u8D77\u6765\u63A2\u7A76\u4E00\u4E0B\u5982\u4F55\u7B80\u5355\u5B9E\u73B0\u5BF9\u8BA1\u7B97\u5C5E\u6027\u7684\u4FA6\u542C\u3002</p><p>\u7B80\u5316\u4E00\u4E0B\u9700\u6C42\uFF0C\u5047\u8BBE\u6B64\u65F6\u4F20\u5165<code>watch</code>\u7684\u4E0D\u518D\u662F\u4E00\u4E2A\u54CD\u5E94\u5F0F\u6570\u636E\uFF0C\u800C\u662F\u4E00\u4E2A<code>getter</code>\u51FD\u6570\uFF0C\u800C\u5728\u8BE5\u51FD\u6570\u5185\u90E8\u6307\u5B9A\u4E86\u5BF9\u4E00\u4E9B\u54CD\u5E94\u5F0F\u6570\u636E\u7684\u4F9D\u8D56\u3002\u73B0\u5728\u7684\u9700\u6C42\u5C31\u662F\uFF1A\u53EA\u8981<code>getter</code>\u51FD\u6570\u5185\u90E8\u6240\u4F9D\u8D56\u7684\u4EFB\u610F\u4E00\u4E2A\u54CD\u5E94\u5F0F\u6570\u636E\u53D1\u751F\u4E86\u53D8\u5316\u5C31\u6267\u884C\u56DE\u8C03\u51FD\u6570<code>cb</code>\u3002\u8BF7\u95EE\uFF0C\u600E\u4E48\u5B9E\u73B0\uFF1F</p><p>\u6B64\u65F6\uFF0C\u6211\u4EEC\u53EF\u4EE5\u8BBE\u7F6E\u4E00\u4E2A\u7C7B\u4F3C<code>getter</code>\u53D8\u91CF\u6765\u50A8\u5B58\u4F20\u5165<code>effect</code>\u7684\u53C2\u6570\u3002\u5BF9\u4F20\u5165<code>watch</code>\u7684\u7B2C\u4E00\u4E2A\u53C2\u6570\u8FDB\u884C\u5224\u65AD\uFF0C\u5047\u5982<code>source</code>\u662F\u4E00\u4E2A\u54CD\u5E94\u5F0F\u6570\u636E\uFF0C\u5C31\u5C06<code>() =&gt; traverse(source)</code>\u8D4B\u503C\u7ED9<code>getter</code>\uFF1B\u800C\u5047\u5982<code>source</code>\u662F\u4E00\u4E2A\u51FD\u6570\uFF0C\u90A3\u5C31\u4E0D\u5E94\u8BE5\u8C03\u7528<code>traverse</code>\uFF0C\u800C\u662F\u76F4\u63A5\u8FDB\u884C\u8D4B\u503C<code>getter = source</code>\uFF0C\u5B9E\u73B0\u4EE3\u7801\u5982\u4E0B\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/253263aeab3549efba4c07a4fccc2ed2~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (93).png"></p><p>\u8FD9\u6837\u5C31\u5B9E\u73B0\u4E86\u5BF9\u7C7B\u4F3C<code>getter</code>\u51FD\u6570\u7684\u4FA6\u542C\uFF0C\u589E\u5F3A\u4E86<code>watch</code>\u7684\u529F\u80FD\u3002</p><h2 id="\u5B9E\u73B0\u5728\u56DE\u8C03\u51FD\u6570\u4E2D\u62FF\u5230\u53D8\u5316\u524D\u540E\u7684\u503C" tabindex="-1"><a class="header-anchor" href="#\u5B9E\u73B0\u5728\u56DE\u8C03\u51FD\u6570\u4E2D\u62FF\u5230\u53D8\u5316\u524D\u540E\u7684\u503C" aria-hidden="true">#</a> \u5B9E\u73B0\u5728\u56DE\u8C03\u51FD\u6570\u4E2D\u62FF\u5230\u53D8\u5316\u524D\u540E\u7684\u503C</h2><p>\u5728\u4FA6\u542C\u5668\u7684\u5B9E\u9645\u5E94\u7528\u4E4B\u4E2D\uFF0C\u6211\u4EEC\u7ECF\u5E38\u9700\u8981\u83B7\u53D6\u88AB\u4FA6\u542C\u6570\u636E\u53D8\u5316\u524D\u540E\u7684\u503C\u3002\u5176\u5B9E\u8981\u60F3\u5B9E\u73B0\u83B7\u5F97\u65B0\u503C<code>newValue</code>\u4E0D\u96BE\uFF0C\u6BCF\u6B21\u5728<code>scheduler</code>\u51FD\u6570\u4E2D\u91CD\u65B0\u6267\u884C\u7684\u526F\u4F5C\u7528\u51FD\u6570\u8FD4\u56DE\u7684\u5C31\u662F\u65B0\u503C\uFF0C\u96BE\u70B9\u5728\u4E8E\u65E7\u503C<code>oldValue</code>\u7684\u83B7\u53D6\uFF1A\u9700\u8981\u5229\u7528<code>effect</code>\u51FD\u6570\u7684<code>lazy</code>\u9009\u9879\u521B\u5EFA\u4E00\u4E2A\u61D2\u6267\u884C\u7684<code>effect</code>\uFF0C\u4ECE\u800C\u901A\u8FC7\u624B\u52A8\u8C03\u7528\u526F\u4F5C\u7528\u51FD\u6570\u6765\u62FF\u5230\u65E7\u503C<code>oldValue</code>\uFF0C\u5177\u4F53\u5B9E\u73B0\u5982\u4E0B\uFF1A</p><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/eb4ea8d26bd646daa3cf2e5f560a3aa6~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (94).png"></p><p>\u8BF7\u6CE8\u610F\u4E0A\u8FF0\u4EE3\u7801\u6700\u540E\u4E00\u90E8\u5206\uFF0C\u6211\u4EEC\u624B\u52A8\u8C03\u7528<code>effectFn</code>\u83B7\u5F97\u7684\u8FD4\u56DE\u503C\u662F\u65E7\u503C<code>oldValue</code>\uFF0C\u65B0\u503C<code>newValue</code>\u53EA\u80FD\u5728<code>sechduler</code>\u4E2D\u83B7\u5F97\u3002</p><h2 id="\u5B9E\u73B0watch\u7ACB\u5373\u6267\u884C" tabindex="-1"><a class="header-anchor" href="#\u5B9E\u73B0watch\u7ACB\u5373\u6267\u884C" aria-hidden="true">#</a> \u5B9E\u73B0<code>watch</code>\u7ACB\u5373\u6267\u884C</h2><p>\u4E0A\u8FF0\u6211\u4EEC\u5DF2\u5B9E\u73B0\u7684<code>watch</code>\u53EA\u4F1A\u5728\u88AB\u4FA6\u542C\u6570\u636E\u53D1\u751F\u53D8\u5316\u65F6\u624D\u4F1A\u6267\u884C\u56DE\u8C03\u51FD\u6570\uFF0C\u800C\u5B9E\u9645\u4E0A\u5728Vue.js\u4E2D\u53EF\u4EE5\u901A\u8FC7\u9009\u9879\u53C2\u6570<code>immediate</code>\u6765\u6307\u5B9A\u56DE\u8C03\u51FD\u6570\u662F\u5426\u7ACB\u5373\u6267\u884C\uFF0C\u90A3\u8FD9\u4E2A\u529F\u80FD\u5E94\u8BE5\u600E\u4E48\u5B9E\u73B0\u5462\uFF1F\u4E8B\u5B9E\u4E0A\uFF0C\u4F60\u51B7\u9759\u5206\u6790\u4E00\u4E0B\u5C31\u4F1A\u53D1\u73B0\uFF0C\u8FD9\u4E2A\u7ACB\u5373\u6267\u884C\u7684\u56DE\u8C03\u51FD\u6570\u548C\u540E\u7EED\u6267\u884C\u672C\u8D28\u4E0A\u6CA1\u6709\u4EFB\u4F55\u5DEE\u522B\uFF0C\u90A3\u4E48\u6211\u4EEC\u53EF\u4E0D\u53EF\u4EE5\u5C06\u8C03\u5EA6\u5668\u51FD\u6570<code>scheduler</code>\u5C01\u88C5\u4E3A\u4E00\u4E2A\u901A\u7528\u7684\u51FD\u6570<code>job</code>\uFF0C\u5206\u522B\u5728\u88AB\u4FA6\u542C\u6570\u636E\u521D\u59CB\u5316\u548C\u53D8\u66F4\u7684\u65F6\u5019\u6267\u884C\u5B83\u5462\uFF1F\u5F53\u7136\u53EF\u4EE5\uFF0C\u5982\u4EE5\u4E0B\u4EE3\u7801\u6240\u793A\uFF1A</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/65f009d465304868bde8c1dd49295c5a~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (95).png"></p><p>\u4EE5\u4E0A\u4FEE\u6539\u540E\u7684<code>watch</code>\u4EE3\u7801\u5B9E\u73B0\u4E86\u5BF9<code>options.immediate</code>\u7684\u652F\u6301\uFF0C\u81F3\u4E8EVue.js\u7684\u4FA6\u542C\u5668\u4E2D\u8FD8\u63D0\u4F9B\u7684\u5176\u4ED6<code>options</code>\uFF0C\u5982<code>flush</code>\uFF0C\u5728\u672C\u6587\u4E2D\u5C31\u4E0D\u4E00\u4E00\u5B9E\u73B0\u4E86\uFF0C\u611F\u5174\u8DA3\u7684\u670B\u53CB\u53EF\u4EE5\u81EA\u5DF1\u52A8\u624B\u5C1D\u8BD5\u5B9E\u73B0\u4E00\u4E0B\u3002</p><h2 id="\u540E\u8BDD" tabindex="-1"><a class="header-anchor" href="#\u540E\u8BDD" aria-hidden="true">#</a> \u540E\u8BDD</h2><p>\u7B14\u8005\u6BD5\u7ADF\u662F\u4E00\u4E2A\u751F\u7269\u4E13\u4E1A\u7684\u5B66\u751F\uFF0C\u4ECA\u5929\u4E0A\u5348\u65E9\u516B\u4E0A\u5206\u5B50\u751F\u7269\uFF0C\u4E0B\u5348\u88AB\u751F\u5316\u7EFC\u5408\u5B9E\u9A8C\u5BA4\u8001\u5E08\u62C9\u53BB\u5B9E\u9A8C\u5BA4\u5E72\u4E86\u4E00\u6574\u4E2A\u4E0B\u5348\u7684\u6D3B\uFF0C\u5C31\u8FD9\u6837\uFF0C\u4ECA\u5929\u767D\u5929\u5C31\u8FD9\u6837\u6CA1\u4E86\uFF0C\u6CA1\u4E86\u554A\uFF01\u5176\u5B9E\u4FA6\u542C\u5668<code>watch</code>\u7684\u5B9E\u73B0\u7EC6\u8282\u8FD8\u6709\u4E0D\u5C11\uFF0C\u5982\u7ADE\u6001\u95EE\u9898\u7684\u89E3\u51B3\uFF0C\u4F46\u662F\u56E0\u4E3A\u4ECA\u5929\u65F6\u95F4\u592A\u7D27\u4E86\uFF0C\u611F\u89C9\u5F88\u4ED3\u4FC3\uFF0C\u5C31\u4E0D\u5728\u672C\u7BC7\u8BE6\u8BF4\u4E86\u3002\u611F\u5174\u8DA3\u7684\u670B\u53CB\u53EF\u4EE5\u53BB\u770B\u770B\u300AVue.js\u8BBE\u8BA1\u4E0E\u5B9E\u73B0\u300B\u8FD9\u672C\u4E66\uFF0C\u8D85\u7EA7\u68D2\u3002</p><h2 id="\u58F0\u660E" tabindex="-1"><a class="header-anchor" href="#\u58F0\u660E" aria-hidden="true">#</a> \u58F0\u660E</h2><ul><li>\u672C\u6587\u5C5E\u4E8E\u8BFB\u4E66\u7B14\u8BB0\u4E00\u7C7B\uFF0C\u662F\u4F5C\u8005\u5728\u62DC\u8BFB \u970D\u6625\u9633 \u5927\u4F6C\u7684\u65B0\u4F5C\u300AVue.js\u8BBE\u8BA1\u4E0E\u5B9E\u73B0\u300B\u9014\u4E2D\uFF0C\u4EE5\u4E66\u4E2D\u5185\u5BB9\u4E3A\u84DD\u672C\uFF0C\u8F85\u4EE5\u4E2A\u4EBA\u5FAE\u672B\u7684\u9053\u884C\u201C\u586B\u5199\u201D\u5B8C\u6210\uFF0C\u63A8\u8350\u8D2D\u4E66\u9605\u8BFB\uFF0C\u5B9A\u6709\u6536\u83B7</li><li>\u6B22\u8FCE\u5927\u4F6C\u65A7\u6B63</li><li>\u65E5\u66F4</li></ul>',38);function a(t,r){return d}var s=c(o,[["render",a]]);export{s as default};
